fun solve(nums: Array<Long>): Long {
    val n = nums.size
    if (n < 3) {
        // Should not happen based on constraints, but handled defensively.
        // If N=1, Inc=[N], Dec=[N]. Sums equal.
        if (n == 1) return -1L
        // If N=2, [a, b]. Peak is b if a < b, or a if a > b.
        // We rely on the binary search for N>=3 structure.
    }

    // 1. Find the peak index using binary search
    var L = 0
    var R = n - 1
    var peakIndex = -1

    while (L <= R) {
        if (L == R) {
            peakIndex = L
            break
        }

        val M = L + (R - L) / 2

        // Check if M is the peak: nums[M] > nums[M+1] and nums[M] > nums[M-1] (if M > 0)

        // Simpler check for unimodal array: compare M with M+1
        if (nums[M] < nums[M+1]) {
            // We are on the increasing slope, peak is to the right
            L = M + 1
        } else {
            // nums[M] >= nums[M+1]. M could be the peak, or we are on the decreasing slope.
            // Search left/at M
            R = M
        }
    }

    // After the loop, L == R, and this is the peak index.
    peakIndex = L

    // 2. Calculate sums

    // Increasing part: indices 0 to peakIndex (inclusive)
    var sumInc: Long = 0
    for (i in 0..peakIndex) {
        sumInc += nums[i]
    }

    // Decreasing part: indices peakIndex to n-1 (inclusive)
    var sumDec: Long = 0
    for (i in peakIndex until n) {
        sumDec += nums[i]
    }

    // 3. Comparison
    if (sumInc > sumDec) {
        return 0L
    } else if (sumDec > sumInc) {
        return 1L
    } else {
        return -1L
    }
}

